apk add --no-cache python3 >/dev/null 2>&1; python3 -c 'import sys,math,json,time;N=int(sys.argv[1]) if len(sys.argv)>1 else 24;lam=float(sys.argv[2]) if len(sys.argv)>2 else 0.82;theta=float(sys.argv[3]) if len(sys.argv)>3 else 0.777;seed=float(sys.argv[4]) if len(sys.argv)>4 else time.time();tau=lambda n:sum(1 for d in range(1,int(abs(n)) + 1) if abs(n) and abs(n)%d==0) if int(abs(n))<5000 else sum(1 for d in range(1,101) if int(abs(n))%d==0);items=[];H=1.0;A=1.0;z=complex(math.cos(seed%6.28318),math.sin(seed%6.28318));ok=True
