    rot=complex(math.cos(theta*(n+1)),math.sin(theta*(n+1))); z=(z*rot)+complex(1/(n+2),lam/(n+2)); care=1-math.exp(-(n+1)/7); verify=1-math.exp(-(n+1)/9); harm_pressure=max(0.0,H); shadow=max(harm_pressure-care*verify,0.0); A=shadow; H=max(0.0,lam*H-(care*verify)/(n+2)); items.append({"n":n,"z":"%.6f%+.6fi"%(z.real,z.imag),"care":round(care,6),"verify":round(verify,6),"H_suffering":round(H,9),"A_shadow":round(A,9),"projection":"possible_harm->shadow_area->film_story_warning_prevention"})
